namespace sv_a4490c794b064a02b33118db00008899.Services;

public record Recipe(int Id, string Title, string Description, int PrepTimeMinutes);

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> SeedData = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Spaghetti Carbonara", "Classic Roman pasta with eggs, pecorino, guanciale, and black pepper.", 30),
            new(2, "Margherita Pizza", "Simple pizza with tomato sauce, fresh mozzarella, and basil.", 45),
            new(3, "Risotto alla Milanese", "Creamy saffron-infused risotto from Milan.", 40),
        },
        [2] = new List<Recipe>
        {
            new(4, "Chicken Tikka Masala", "Grilled chicken in a creamy spiced tomato sauce.", 50),
            new(5, "Palak Paneer", "Fresh spinach cooked with paneer cubes and aromatic spices.", 35),
            new(6, "Biryani", "Fragrant layered rice dish with marinated meat and saffron.", 90),
        },
        [3] = new List<Recipe>
        {
            new(7, "Tacos al Pastor", "Marinated pork tacos with pineapple, cilantro, and onion.", 60),
            new(8, "Guacamole", "Fresh avocado dip with lime, cilantro, jalapeño, and tomato.", 10),
            new(9, "Enchiladas Verdes", "Corn tortillas filled with chicken and topped with green salsa.", 45),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        if (SeedData.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@using sv_a4490c794b064a02b33118db00008899.Services
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@inject NavigationManager Navigation
@implements IDisposable

<PageTitle>Recipes</PageTitle>

<h1>Recipes</h1>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_error</p>
        <button class="btn btn-outline-danger" @onclick="Retry">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes...</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <p><em>Refreshing…</em></p>
    }

    <table class="table">
        <thead>
            <tr>
                <th>Title</th>
                <th>Description</th>
                <th>Prep Time (min)</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var recipe in DisplayedRecipes)
            {
                <tr>
                    <td>@recipe.Title</td>
                    <td>@recipe.Description</td>
                    <td>@recipe.PrepTimeMinutes</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private string? _error;
    private bool _isRefreshing;
    private int _loadedCuisineId;
    private CancellationTokenSource? _cts;

    private IEnumerable<Recipe> DisplayedRecipes
    {
        get
        {
            if (_recipes is null) return Enumerable.Empty<Recipe>();

            return Sort?.ToLowerInvariant() switch
            {
                "newest" => _recipes.OrderByDescending(r => r.Id),
                "popular" => _recipes.OrderBy(r => r.PrepTimeMinutes),
                _ => _recipes,
            };
        }
    }

    protected override Task OnParametersSetAsync()
    {
        // Only reload when the cuisine changes, not when sort changes.
        if (CuisineId != _loadedCuisineId)
        {
            return LoadRecipesAsync();
        }

        return Task.CompletedTask;
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request.
        await CancelPendingRequestAsync();

        _cts = new CancellationTokenSource();
        var cancellationToken = _cts.Token;
        var cuisineId = CuisineId;

        _error = null;
        _isRefreshing = _recipes is not null;

        if (!_isRefreshing)
        {
            StateHasChanged();
        }

        try
        {
            var results = await RecipeService.GetByCuisineAsync(cuisineId, cancellationToken);

            // Guard against applying stale results if cancelled between await and here.
            if (cancellationToken.IsCancellationRequested) return;

            _recipes = results;
            _loadedCuisineId = cuisineId;
            _isRefreshing = false;
        }
        catch (OperationCanceledException)
        {
            // Request was intentionally cancelled — nothing to do.
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", cuisineId);
            _error = "The request timed out. Please try again.";
            _isRefreshing = false;
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", cuisineId);
            _error = "Something went wrong loading recipes. Please try again.";
            _isRefreshing = false;
        }
    }

    private Task Retry() => LoadRecipesAsync();

    private async Task CancelPendingRequestAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
            _cts = null;
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

